mapper.select:
SELECT b.*, p.name as property_name, p.address as property_address, t.name as tenant_name, l.start_date as lease_start_date, l.end_date as lease_end_date FROM bills b LEFT JOIN leases l ON b.lease_id = l.id LEFT JOIN properties p ON l.property_id = p.id OR b.property_id = p.id LEFT JOIN tenants t ON l.tenant_id = t.id OR b.tenant_id = t.id WHERE b.landlord_id = #{landlordId}
AND b.status = #{status}
AND b.bill_type = #{billType}
AND (l.tenant_id = #{tenantId} OR b.tenant_id = #{tenantId})
AND b.lease_id = #{leaseId}
ORDER BY b.due_date DESC

SELECT COALESCE(SUM(paid_amount), 0) FROM bills
WHERE landlord_id = #{landlordId}
  AND status = '已支付'
  AND YEAR(paid_date) = #{year}
  AND MONTH(paid_date) = #{month}
